            const sigLayer = from.layer + sig.t * (to.layer - from.layer);
            const sigDist = Math.abs(sigLayer - waveFront);
            sigAlpha = Math.min(1, sigAlpha + Math.exp(-(sigDist * sigDist) / 0.5) * 0.5);
          }
          ctx.globalAlpha = Math.min(0.75, sigAlpha);
          ctx.fillStyle = inCascade && sigAlpha > 0.55 ? COL.signalCascade : COL.signal;
          ctx.beginPath();
          ctx.arc(pt.x, pt.y, sig.size, 0, TAU);
          ctx.fill();
        }
      }

      // Draw nodes (back layers first for depth)
      const sortedNodes = [...s.nodes].sort((a, b) => a.layer - b.layer);

      for (const node of sortedNodes) {
        const depth = node.layer * 1.5;
        const nx = node.x + mx * parallaxStr * (1 + depth * 0.3);
        const ny = node.y + my * parallaxStr * (1 + depth * 0.3);
        const breath = 1 + node.pulse;
        const r = node.baseRadius * breath;

        // Glow halo
        const glowR = r * 2.8;
        const glowAlpha = (0.12 + node.cascadeGlow * 0.25);
        ctx.globalAlpha = glowAlpha;
        const glowGrad = ctx.createRadialGradient(nx, ny, r * 0.5, nx, ny, glowR);
        glowGrad.addColorStop(0, COL.nodeGlow);
        glowGrad.addColorStop(1, "transparent");
        ctx.fillStyle = glowGrad;
        ctx.beginPath();
        ctx.arc(nx, ny, glowR, 0, TAU);
        ctx.fill();

        // Outer halo (subtle)
        ctx.globalAlpha = 0.06 + node.cascadeGlow * 0.1;
        ctx.fillStyle = COL.nodeGlow;
        ctx.beginPath();
        ctx.arc(nx, ny, r * 4.5, 0, TAU);
        ctx.fill();

        // Node body
        const fillAlpha = 0.55 + node.pulse * 0.2 + node.cascadeGlow * 0.3;
        const fillColor = node.cascadeGlow > 0.1 ? COL.nodeCascade : COL.nodeFill;

        ctx.globalAlpha = Math.min(0.85, fillAlpha);
        ctx.fillStyle = fillColor;
        ctx.beginPath();
        ctx.arc(nx, ny, r, 0, TAU);
        ctx.fill();

        // Node stroke
        ctx.globalAlpha = 0.28 + node.cascadeGlow * 0.2;
        ctx.strokeStyle = COL.nodeStroke;
        ctx.lineWidth = 0.7;
        ctx.beginPath();
        ctx.arc(nx, ny, r, 0, TAU);
        ctx.stroke();
      }

      ctx.globalAlpha = 1;
      animationId = requestAnimationFrame(draw);
    };

    resize();
    window.addEventListener("resize", debouncedResize);
    window.addEventListener("mousemove", onMouseMove, { passive: true });
    animationId = requestAnimationFrame(draw);

    return () => {
      window.removeEventListener("resize", debouncedResize);
      window.removeEventListener("mousemove", onMouseMove);
      if (resizeTimer) clearTimeout(resizeTimer);
      cancelAnimationFrame(animationId);
    };
  }, [initState]);

  return (
    <canvas
      ref={canvasRef}
      aria-hidden="true"
      className="pointer-events-none fixed inset-0 z-0"
    />
  );
}

